(7,'test','',NULL,'production','important',NULL,NULL,'','','','','','',1,'2026-07-06 10:37:52','2026-07-06 10:37:52',0),
(8,'出血与安全区','印刷品未留出血或文字距裁切线过近，裁切时出现露白或切掉文字。','出血统一留 3mm；文字与重要元素距裁切线 ≥3mm；出稿前检查安全区，关键内容不跨出血线。','design','important','design',NULL,'纸制品','印刷',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(9,'专色与品牌色','品牌色/LOGO 用四色叠印，批次间偏色明显，与品牌视觉规范不符。','品牌色指定专色（潘通色号）；深底白字垫白墨；打样对照潘通色卡确认后再批量。','design','important','design,mass',NULL,'全品类','专色印刷',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(10,'最小线宽与字号','丝印/烫金线条过细或字号过小，成品断线、糊字、缺笔。','丝印/烫金线宽 ≥0.3mm；最小字号视工艺咨询工厂；过细文字改凸印或 UV 工艺。','design','fatal','design,sample',NULL,'全品类','丝印/烫金',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(11,'异形模切拐角','异形刀模拐角过尖（<90°），模切后纸张撕裂、边缘毛糙。','拐角尽量 ≥90° 或做圆角（R≥2mm）；尖角处加圆角过渡；与刀模厂确认拐角工艺。','design','important','design',NULL,'纸制品','模切',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(12,'CMYK 与屏幕色差','按 RGB 屏幕效果定稿，转 CMYK 后深色/荧光色变暗，成品与预期偏差大。','设计文件统一用 CMYK 模式；深色/荧光色必须打样确认，不能只看屏幕；必要时用专色补色。','design','important','design,sample',NULL,'全品类','四色印刷',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(13,'材质与工艺匹配','珠光纸大面积深色吸墨不均；镭射纸烫金温度过高糊版；亚克力热弯未预留回弹量。','珠光纸慎用大面积深色，改局部色块；镭射纸烫金降温试压；亚克力热弯按材质预留回弹余量。','design','fatal','design,sample',NULL,'特殊材质','烫金/印刷',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(14,'双面正反面对齐','双面印刷/模切未标天地线方向，正反面错位、图案不对齐。','文件标注天地线与咬口方向；模切件图纹与刀模方向一致；打样核对正反套准。','design','suggestion','design,mass',NULL,'双面印刷','双面印',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(15,'IP 元素安全区与授权','授权素材被二次修改比例、裁切关键元素，或漏署名，导致授权方拒收或侵权。','严格按授权素材原图使用，不可拉伸/裁切主体；保留作者署名区；超出授权范围需重新申请。','design','fatal','design',NULL,'IP周边','全工艺',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(16,'打样与大货差异','打样单件精修与大货批量存在公差，未约定允差导致大货到货与打样不符。','下单前书面约定色差 ΔE 与尺寸公差范围；大货首件对照打样签字确认后再批量。','production','important','sample,mass',NULL,'全品类','全工艺',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(17,'色差允收标准','大货批次间色差未抽检，整批偏色流入下道工序。','按批次抽检色差，ΔE≤3 为合格；超差批次拒收或返工；留存打样作比对基准。','production','important','mass',NULL,'印刷品','四色印刷',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(18,'数量损耗加放','按净数量下单未加损耗，不良与裁切损耗导致交货不够数。','印刷加放 5%~10%，异形/特殊工艺 10%~15%；下单量 = 净数量 + 损耗，提前与客户说明。','production','important','mass',NULL,'全品类','印刷/模切',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(19,'特殊工艺排产周期','烫金/击凸/UV 需排队排产，旺季未提前下单导致延期。','特殊工艺提前 7~10 天下单；旺季预留排产缓冲；与工厂确认交期后再回复客户。','production','important','sample,mass',NULL,'全品类','烫金/击凸/UV',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(20,'来料入厂检验','来料（纸张克重/厚度、膜厚、色牢度）未抽检直接上线，不良料流入成品。','入厂按批次抽检克重/厚度/色牢度，不合格批次拒收并记录；关键料件首件确认再批量上线。','production','fatal','mass',NULL,'全品类','全工艺',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(21,'包装防刮防压','异形件/镭射件直接堆叠运输，互相刮花、磨损。','异形/易刮花件用隔板 + 气泡袋单件隔离；外箱标毛重与向上标志，避免重压与倒置。','production','important','package',NULL,'异形/易刮花件','包装',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(22,'大货首件确认','大货开机未做首件确认直接批量，整批错误报废。','开机首件由质检/项目负责人签字确认后再批量；首件留存至批次交付完毕。','production','fatal','mass',NULL,'全品类','全工艺',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0),
(23,'IP 授权合规与包装标识','IP 元素超出授权范围/期限使用，或包装漏印授权信息，导致侵权下架。','生产前核验授权范围与期限；包装按授权方要求印授权信息与标识；超期/超范围需重新申请授权。','production','fatal','mass,package',NULL,'IP周边','全工艺',NULL,NULL,NULL,NULL,1,'2026-07-07 11:23:35','2026-07-07 11:23:35',0);
