(352,1,'admin','删除 #57','灵感库','DELETE','/api/inspirations/57','127.0.0.1','Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/150.0.0.0 Safari/537.36','{\"id\":57}','{\"id\":57,\"inspiration_type\":\"peripheral\",\"categories\":\"peripheral\",\"title\":\"真正的神谷无需谷美\",\"source_platform\":\"小红书\",\"source_type\":\"小红书\",\"source_name\":\"一场新的暴雪\",\"link\":\"https://www.xiaohongshu.com/explore/65a7b2d20000000028029606?source=webshare&xhsshare=pc_web&xsec_token=AB6Da9E545npw8d-DYdPKBVyGtEdDUVW2PYK6kXz5JhDg=&xsec_source=pc_share\",\"source_url\":\"https://www.xiaohongshu.com/explore/65a7b2d20000000028029606?source=webshare&xhsshare=pc_web&xsec_token=AB6Da9E545npw8d-DYdPKBVyGtEdDUVW2PYK6kXz5JhDg=&xsec_source=pc_share\",\"link_status\":\"ok\",\"link_http_code\":200,\"link_checked_at\":\"2026-07-01 11:35:20\",\"author\":\"一场新的暴雪\",\"author_url\":null,\"screenshot\":null,\"cover_image\":\"insp_1782808975913_fkjks8.webp\",\"images\":\"insp_1782808975913_fkjks8.webp,insp_1782808975323_aeywjo.webp,insp_1782808975568_8zufxu.webp,insp_1782808976335_z4lan7.webp,insp_1782808976723_2daj0o.webp\",\"image_texts\":\"[{\\\"file\\\":\\\"insp_1782808975913_fkjks8.webp\\\",\\\"text\\\":\\\"（无实质内容）\\\"},{\\\"file\\\":\\\"insp_1782808975323_aeywjo.webp\\\",\\\"text\\\":\\\"（无实质内容）\\\"},{\\\"file\\\":\\\"insp_1782808975568_8zufxu.webp\\\",\\\"text\\\":\\\"命运之轮\\\"},{\\\"file\\\":\\\"insp_1782808976335_z4lan7.webp\\\",\\\"text\\\":\\\"（无实质内容）\\\"},{\\\"file\\\":\\\"insp_1782808976723_2daj0o.webp\\\",\\\"text\\\":\\\"（无实质内容）\\\"}]\",\"video_url\":null,\"thumbnail\":null,\"category_tag_ids\":null,\"craft_tag_ids\":null,\"ip_tag_ids\":\"63\",\"scene_tag_ids\":null,\"application_scenario\":null,\"reference_value\":\"二次元周边需注重高颜值视觉设计与精美印图，以此提升产品吸引力并激发粉丝情感共鸣。\",\"post_tags\":\"代号鸢,游戏周边,代号鸢孙策,代号鸢刘辩,代号鸢傅融,代号鸢袁基,代号鸢左慈\",\"description\":\"救命啊美晕了……云居河你是我的神！\\n#代号鸢[话题]# #游戏周边[话题]##代号鸢孙策[话题]# #代号鸢刘辩[话题]# #代号鸢傅融[话题]# #代号鸢袁基[话题]# #代号鸢左慈[话题]#\",\"content_summary\":\"【标题】云居河《代号鸢》“命运之轮”主题周边产品展示\\n\\n【内容总结】\\n本篇社交媒体帖子主要展示了由“云居河”出品的《代号鸢》游戏同人周边物料。发帖者对产品的视觉呈现给予了极高评价，直呼“美晕了”。结合标签与图文信息可知，该系列周边涵盖了游戏内的高人气角色，包括孙策、刘辩、傅融、袁基和左慈。图中识别到的“命运之轮”字样，推测为本次周边企划的主题名称或核心产品的命名。整体来看，这是一组以高颜值视觉设计和角色IP为核心的二次元周边商品，凭借精美的印图与设计在玩家群体中引发了强烈的情感共鸣。\\n\\n【关键要点】\\n1. 核心IP：《代号鸢》及五位高人气男主（孙策、刘辩、傅融、袁基、左慈）。\\n2. 出品方/社团：云居河。\\n3. 主题系列：“命运之轮”主题企划。\\n4. 产品特征：以高颜值和精美视觉设计为核心卖点，注重图案表现力。\\n5. 目标受众：游戏核心玩家及二次元周边收藏爱好者。\\n\\n【适用场景】\\n适用于二次元游戏IP周边产品（如塔罗牌、徽章、镭射票、色纸、亚克力立牌等）的营销宣发、同人社团新品预告，以及小红书、微博等社交媒体的粉丝种草推广场景。\",\"notes\":null,\"collect_time\":null,\"collector\":null,\"collection_status\":\"collected\",\"folder_id\":null,\"is_featured\":0,\"is_pinned\":0,\"like_count\":11000,\"save_count\":1957,\"comment_count\":0,\"view_count\":1,\"play_count\":0,\"is_adopted\":0,\"application_result\":null,\"application_date\":null,\"is_sensitive\":0,\"sensitive_reason\":null,\"related_project_ids\":null,\"create_user_id\":1,\"create_time\":\"2026-06-30 16:42:53\",\"update_time\":\"2026-07-08 17:29:52\",\"is_delete\":0}','inspiration',57,0,NULL,1,NULL,'2026-07-17 11:56:35'),
